const toneFor=(label)=>{const l=label.toLowerCase();if(l.includes("approve"))return"approve";if(l.includes("cancel"))return"cancel";if(l.includes("dispatch"))return"dispatch";if(l.includes("deliver"))return"deliver";if(l.includes("deactivate")||l.includes("disable")||l.includes("pause")||l.includes("failed"))return"deactivate";if(l.includes("change")||l.includes("duplicate")||l.includes("retry"))return"change";if(l.includes("credit")||l.includes("save")||l.includes("enable"))return"credit";return"";};
