function setMode(mode){genericTablePanel.hidden=mode!=="generic";detailGrid.hidden=mode!=="generic";ordersWorkspace.hidden=mode!=="orders";managementWorkspace.hidden=mode!=="management";routesWorkspace.hidden=mode!=="routes";}
