function renderSummary(page,compact){summaryGrid.classList.toggle("compact",compact);summaryGrid.innerHTML="";(page.metrics||page.summary||[]).forEach((item)=>summaryGrid.appendChild(page.metrics?metricCard(item):summaryCard(item)));}
function renderFilters(filters){if(!filters){filterBar.hidden=true;filterSlots.forEach(({group,body})=>{group.hidden=true;body.innerHTML="";});return;}filterBar.hidden=false;filterSlots.forEach((slot,i)=>{const cfg=filters[i];if(!cfg){slot.group.hidden=true;slot.body.innerHTML="";return;}slot.group.hidden=false;slot.label.textContent=cfg.label;slot.body.innerHTML="";if(cfg.type==="select"){const select=document.createElement("select");select.className="field-select";cfg.options.forEach((opt)=>{const o=document.createElement("option");o.textContent=opt;select.appendChild(o);});slot.body.appendChild(select);}else{cfg.options.forEach((opt,j)=>slot.body.appendChild(btn(opt,`filter-pill${j===0?" is-active":""}`)));}});}
function renderSchemeBanner(page){if(!page.scheme){schemeBanner.hidden=true;schemeBanner.innerHTML="";return;}schemeBanner.hidden=false;schemeBanner.innerHTML=`<div><p class="eyebrow">${page.scheme.kicker}</p><h4 class="banner-title">${page.scheme.title}</h4><p class="banner-copy">${page.scheme.copy}</p><div class="banner-meta">${page.scheme.chips.map((c)=>`<span class="banner-chip">${c}</span>`).join("")}</div></div><button class="banner-cta" type="button">${page.scheme.action}</button>`;}
