function renderTableSkeleton(cols,rows){tableHead.innerHTML="";tableBody.innerHTML="";const hr=document.createElement("tr");cols.forEach((c)=>{const th=document.createElement("th");th.scope="col";th.textContent=c;hr.appendChild(th);});tableHead.appendChild(hr);Array.from({length:rows}).forEach(()=>{const tr=document.createElement("tr");cols.forEach((_,i)=>{const td=document.createElement("td");const div=document.createElement("div");div.className=`skeleton-line ${i===0?"cell-lg":i<3?"cell-md":"cell-sm"}`;td.appendChild(div);tr.appendChild(td);});tableBody.appendChild(tr);});}
