function renderGenericDetail(cfg,kicker,title,note,body,bullet){kicker.textContent=cfg.kicker;title.textContent=cfg.title;note.textContent=cfg.note;if(cfg.mode==="skeleton-list"){body.innerHTML=`<div class="stacked-skeleton"><div class="rail-card"><div class="skeleton-line short"></div><div class="skeleton-line"></div><div class="skeleton-line medium"></div></div><div class="rail-card"><div class="skeleton-line short"></div><div class="skeleton-line"></div><div class="skeleton-line medium"></div></div></div>`;return;}if(cfg.mode==="skeleton-hero"){body.innerHTML=`<div class="hero-skeleton"><div class="hero-block"></div><div class="hero-grid"><div class="mini-block"></div><div class="mini-block"></div><div class="mini-block"></div></div></div>`;return;}body.innerHTML=`<div class="list-block">${cfg.items.map((item)=>`<div class="list-row"><div class="list-line">${bullet?'<span class="list-bullet" aria-hidden="true"></span>':`<span class="list-kpi">${item.kpi||item.label}</span>`}<div><strong>${item.title}</strong><p class="list-copy">${item.copy}</p></div></div><span class="list-label">${item.kpi||item.label||""}</span></div>`).join("")}</div>`;}
function renderOrders(page,id=page.table.selectedId){page.table.selectedId=id;ordersTableHead.innerHTML="";ordersTableBody.innerHTML="";const hr=document.createElement("tr");page.table.columns.forEach((c,i)=>{const th=document.createElement("th");th.scope="col";if(i===0)th.className="check-col";th.textContent=i===0?"Sel":c;hr.appendChild(th);});ordersTableHead.appendChild(hr);page.table.rows.forEach((row)=>{const tr=document.createElement("tr");if(row.id===page.table.selectedId)tr.classList.add("is-selected");tr.innerHTML=`<td class="check-col"><span class="checkmark${row.selected?" is-selected":""}">${row.selected?"x":""}</span></td><td>${stack(row.retailer,"orders-primary","orders-secondary")}</td><td>${stack(row.route,"orders-primary","orders-secondary")}</td><td>${stack(row.value,"orders-primary","orders-secondary")}</td><td>${stack(row.payment,"orders-primary","orders-secondary")}</td><td>${statusPill(row.status.label,row.status.tone)}</td><td>${stack(row.created,"orders-primary","orders-secondary")}</td>`;const actions=document.createElement("td");actions.className="orders-actions";["Approve order","Cancel order","Mark dispatched","Mark delivered"].forEach((label)=>actions.appendChild(stopBubble(btn(shortLabel(label),`row-action ${toneFor(label)}`))));tr.appendChild(actions);tr.addEventListener("click",()=>renderOrders(page,row.id));ordersTableBody.appendChild(tr);});const row=page.table.rows.find((r)=>r.id===page.table.selectedId)||page.table.rows[0];const d=page.detail;bulkActions.innerHTML=`<span class="bulk-meta">${page.bulk.selectedCount} selected | ${page.bulk.summary}</span>${page.bulk.actions.map((a,i)=>`<button class="bulk-button${i===1?" primary":""}" type="button">${a}</button>`).join("")}`;orderDetailKicker.textContent="Order detail";orderDetailTitle.textContent=`${row.retailer.primary} | ${row.id}`;orderDetailSync.className=`panel-note sync-badge ${d.sync.tone}`;orderDetailSync.textContent=d.sync.label;orderDetailBody.innerHTML=`<div class="detail-card"><div><p class="detail-order-id">${row.id}</p><p class="detail-copy">${row.retailer.primary}, ${row.retailer.secondary}</p></div><span class="inline-pill ${row.status.tone}">${row.status.label}</span></div><div class="order-summary-grid"><div class="order-summary-card"><span class="detail-key">Order value</span><span>${row.value.primary}</span></div><div class="order-summary-card"><span class="detail-key">Expected delivery</span><span>${d.expectedDeliveryDate}</span></div><div class="order-summary-card"><span class="detail-key">Payment mode</span><span>${row.payment.primary}</span></div><div class="order-summary-card"><span class="detail-key">Sync status</span><span>${d.sync.label}</span></div></div><div><p class="eyebrow">Order items</p><div class="order-items">${d.items.map((item)=>`<div class="order-items-row"><div><strong>${item.name}</strong><p class="order-items-sub">${item.sub}</p></div><span class="order-items-qty">${item.qty}</span></div>`).join("")}</div></div><div class="order-action-stack">${d.actions.map((a,i)=>`<button class="order-action-button ${toneFor(a)}${i===0?" primary":""}" type="button">${a}</button>`).join("")}</div>`;}
