function renderPage(key){const page=pages[key];if(!page)return;pageKicker.textContent=page.kicker;pageTitle.textContent=page.title;pageDescription.textContent=page.description;pageBadge.textContent=page.badge;tableTitle.textContent=page.tableTitle||"Operational queue";tableNote.textContent=page.tableNote||"Sticky headers enabled";quickSearch.placeholder=page.searchPlaceholder;renderActions(page);if(page.mode==="dashboard"){renderSummary(page,false);renderFilters(null);renderSchemeBanner(page);renderRouteSummary(page);setMode("generic");renderGenericTable(page);renderGenericDetail(page.detailA,detailAKicker,detailATitle,detailANote,detailABody,false);renderGenericDetail(page.detailB,detailBKicker,detailBTitle,detailBNote,detailBBody,true);}else if(page.mode==="orders"){renderSummary(page,true);renderFilters(page.filters);renderSchemeBanner({});renderRouteSummary({});setMode("orders");renderOrders(page);}else if(page.mode==="management"){renderSummary(page,true);renderFilters(page.filters);renderSchemeBanner({});renderRouteSummary({});setMode("management");renderManagement(page);}else if(page.mode==="routes"){renderSummary(page,true);renderFilters(null);renderSchemeBanner({});renderRouteSummary({});setMode("routes");renderRoutes(page);}else{renderSummary(page,true);renderFilters(null);renderSchemeBanner({});renderRouteSummary({});setMode("generic");renderGenericTable(page);renderGenericDetail(page.detailA,detailAKicker,detailATitle,detailANote,detailABody,false);renderGenericDetail(page.detailB,detailBKicker,detailBTitle,detailBNote,detailBBody,true);}navItems.forEach((item)=>item.classList.toggle("is-active",item.dataset.page===key));sidebar.classList.remove("is-open");sidebarToggle.setAttribute("aria-expanded","false");}
navItems.forEach((item)=>item.addEventListener("click",()=>{
  const targetPage = item.dataset.page;
  if(targetPage === "products") return; // Handled by inline onclick in HTML
  history.pushState(null, '', '?page=' + targetPage);
  renderPage(targetPage);
}));
sidebarToggle.addEventListener("click",()=>{const open=sidebar.classList.toggle("is-open");sidebarToggle.setAttribute("aria-expanded",String(open));});
document.addEventListener("click",(event)=>{if(window.innerWidth>900||!sidebar.classList.contains("is-open"))return;if(!sidebar.contains(event.target)&&!sidebarToggle.contains(event.target)){sidebar.classList.remove("is-open");sidebarToggle.setAttribute("aria-expanded","false");}});
const urlParams = new URLSearchParams(window.location.search);
const initPage = urlParams.get('page') || "dashboard";
renderPage(initPage);


